window.navigateToFloor = function(house, floorNumber) {
  const floorIndex = parseInt(floorNumber);
  if (window.flsFullpage) {
    window.flsFullpage.moveToSection(1);
  }
  const tabButtons = document.querySelectorAll(".house .tabs__title");
  if (house.toLowerCase() === "east" && tabButtons[0]) {
    tabButtons[0].click();
  } else if (house.toLowerCase() === "west" && tabButtons[1]) {
    tabButtons[1].click();
  }
  setTimeout(() => {
    const targetSwiper = house.toLowerCase() === "east" ? window.swipers.eastHouse : window.swipers.westHouse;
    if (targetSwiper) {
      targetSwiper.slideTo(floorIndex, 800);
    }
  }, 600);
};
document.addEventListener("click", (e) => {
  const poly = e.target.closest(".polygon-area");
  if (poly) {
    const parent = poly.closest("g");
    if (parent) {
      const house = parent.getAttribute("data-house");
      const floor = parent.getAttribute("data-floor");
      if (house && floor) {
        window.navigateToFloor(house, floor);
      }
    }
  }
});
